"use client";

import {
  ClientSideSuspense,
  LiveblocksProvider,
  RoomProvider,
  useMutation,
  useStorage,
} from "@liveblocks/react";

const roomId = `like-button-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;

function LikeButtonInner() {
  const likes = useStorage((root) => root.likes);

  const increment = useMutation(({ storage }) => {
    storage.set("likes", (storage.get("likes") ?? 0) + 1);
  }, []);

  return (
    <div>
      <button id="like-button" onClick={increment}>
        Like
      </button>
      <span id="like-count">{likes}</span>
    </div>
  );
}

export default function LikeButton() {
  return (
    <LiveblocksProvider
      publicApiKey={process.env.NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY!}
    >
      <RoomProvider id={roomId} initialStorage={{ likes: 0 }}>
        <ClientSideSuspense fallback={<span id="like-count">0</span>}>
          <LikeButtonInner />
        </ClientSideSuspense>
      </RoomProvider>
    </LiveblocksProvider>
  );
}

import LikeButton from "./LikeButton";

export const metadata = {
  title: "Liveblocks Like Button",
  description: "Collaborative like button using Liveblocks Storage",
};

export default function Home() {
  return (
    <main>
      <h1>Liveblocks Like Button</h1>
      <LikeButton />
    </main>
  );
}

